sequence.script:
var payload = mc.getPayloadJSON();
var policyId = mc.getProperty("policyId");

var now = new Date();

function formatDate(date) {
    var yyyy = date.getFullYear();
    var mm = ("0" + (date.getMonth() + 1)).slice(-2);
    var dd = ("0" + date.getDate()).slice(-2);
    return yyyy + "-" + mm + "-" + dd;
}

function formatTimestamp(date) {
    return date.getFullYear().toString() +
        ("0" + (date.getMonth() + 1)).slice(-2) +
        ("0" + date.getDate()).slice(-2) +
        ("0" + date.getHours()).slice(-2) +
        ("0" + date.getMinutes()).slice(-2) +
        ("0" + date.getSeconds()).slice(-2) +
        ("00" + date.getMilliseconds()).slice(-3);
}

var reinstateTermStartDate = formatDate(now);

// +1 Year -1 Day
var endDate = new Date(now);
endDate.setFullYear(endDate.getFullYear() + 1);
endDate.setDate(endDate.getDate() - 1);

var reinstateTermEndDate = formatDate(endDate);

var premium = 0;

if (payload.money && payload.money.amountValue) {
    premium = Number(payload.money.amountValue);
}

var feePercentage = 2; // 2%

var grossFees = 0;
var totalPremium = 0;

if (premium > 0) {
    grossFees = premium * (feePercentage / 100);
    totalPremium = premium + grossFees;

    grossFees = grossFees.toFixed(2);
    totalPremium = totalPremium.toFixed(2);
}

var reinstatementId = "";

if (payload.reinstatementId && payload.reinstatementId !== "") {
    reinstatementId = payload.reinstatementId;
} else {
    reinstatementId = "RES-" + formatTimestamp(now);
}


var result = {
    policyStatusCode: "PAYMENT_PENDING",
    termStartDate: reinstateTermStartDate || "",
    termEndDate: reinstateTermEndDate || "",
    reinstatements: [
        {
            policyNumber: policyId || "",
            quoteId: (payload.quote && payload.quote.quoteId) || "",
            reinstatementId: reinstatementId,
            policyStatusCode: "PAYMENT_PENDING",
            policyEvent: payload.policyEvent || "",
            reinstateTermStartDate: reinstateTermStartDate,
            reinstateTermEndDate: reinstateTermEndDate,
            pricing: {
                totalPremium: totalPremium || 0,
                grossFees: grossFees || 0,
                amounts: [
                    {
                        amountTypeCode: "PREMIUM",
                        amountValue: premium > 0 ? premium.toFixed(2) : 0,
                        currencyCode: (payload.money && payload.money.currencyCode) || "USD"
                    },
                    {
                        amountTypeCode: "FEE",
                        amountValue: grossFees || 0,
                        currencyCode: (payload.money && payload.money.currencyCode) || "USD"
                    }
                ]
            }
        }
    ]
};

mc.setPayloadJSON(result);

mc.setProperty("contentUpdate", JSON.stringify(result));
mc.setPayloadJSON(result);

var firstReinstatement = {};
if (result.reinstatements && result.reinstatements.length > 0) {
    firstReinstatement = result.reinstatements[0];
}

mc.setProperty("reinstatements", JSON.stringify(firstReinstatement));

then.script:
var reinstatementStr = mc.getProperty("reinstatements");

var reinstatementObj = {};

if (reinstatementStr) {
    reinstatementObj = JSON.parse(reinstatementStr);
}

reinstatementObj.assessmentTypeCode = "REINSTATEMENT_EVALUATION";
reinstatementObj.assessmentStatusCode = "APPROVED";
reinstatementObj.outstandingAmount = 0;

mc.setPayloadJSON(reinstatementObj);

var reinstatementStr = mc.getProperty("reinstatements");

var reinstatementObj = {};

if (reinstatementStr) {
    reinstatementObj = JSON.parse(reinstatementStr);
}

reinstatementObj.status = "SUCCESS";
reinstatementObj.message = "Policy reinstated successfully";

mc.setPayloadJSON(reinstatementObj);
